-{"id":"bd-1c6.11","title":"Examples Validation Test Suite","description":"# Examples Validation Test Suite

## Purpose

Automated test suite that validates all examples compile, run correctly, and produce expected output. This ensures examples remain working as the library evolves.

## Test Architecture

### 1. Compile-time Validation

Create `tests/examples_compile.rs`:

```rust
//\! Validates all examples compile successfully
//\! Run with: cargo test --test examples_compile

use std::process::Command;
use tracing::{info, error, warn};

fn init_logging() {
    let _ = tracing_subscriber::fmt()
        .with_max_level(tracing::Level::INFO)
        .try_init();
}

#[test]
fn all_examples_compile() {
    init_logging();

    let examples = [
        "01_hello_terminal",
        "02_colors", 
        "03_styles",
        "04_drawing",
        "05_scissoring",
        "06_opacity",
        "07_input",
        "08_animation",
        "09_text_buffer",
        "10_dashboard",
        "editor",
    ];

    let mut failures = Vec::new();

    for example in examples {
        info\!(example, "Checking compilation");

        let output = Command::new("cargo")
            .args(["build", "--example", example])
            .output()
            .expect("Failed to execute cargo");

        if \!output.status.success() {
            error\!(
                example,
                stderr = String::from_utf8_lossy(&output.stderr).as_ref(),
                "Compilation FAILED"
            );
            failures.push(example);
        } else {
            info\!(example, "Compilation OK");
        }
    }

    if \!failures.is_empty() {
        panic\!("Examples failed to compile: {:?}", failures);
    }
}
```

### 2. Runtime Smoke Tests

For examples that dont require interactive input, verify they run without crashing:

```rust
#[test]
fn example_hello_runs() {
    init_logging();
    info\!("Running hello terminal example");

    // Run with timeout (example should exit on any input)
    let output = Command::new("cargo")
        .args(["run", "--example", "hello", "--"])
        .timeout(std::time::Duration::from_secs(2))
        .output();

    // Timeout is expected (waiting for input), but shouldnt crash
    match output {
        Ok(out) => {
            info\!(
                status = ?out.status,
                "Example completed"
            );
        }
        Err(e) if e.kind() == std::io::ErrorKind::TimedOut => {
            info\!("Example timed out (expected)");
        }
        Err(e) => {
            panic\!("Example failed unexpectedly: {e}");
        }
    }
}
```

### 3. Output Verification

For non-interactive examples, capture and verify output:

```rust
#[test]
fn example_colors_output() {
    init_logging();

    // Some examples can be run with TERM=dumb to get basic output
    let output = Command::new("cargo")
        .args(["run", "--example", "colors_demo"])
        .env("TERM", "dumb")
        .output()
        .expect("Failed to run example");

    let stdout = String::from_utf8_lossy(&output.stdout);
    info\!(output_len = stdout.len(), "Captured output");

    // Verify expected content
    assert\!(stdout.contains("Color Demo") || output.status.success(),
           "Example should produce expected output");
}
```

### 4. CI Integration Script

Create `scripts/test_examples.sh`:

```bash
#\!/bin/bash
# Test all examples for compilation and basic execution
# Usage: ./scripts/test_examples.sh

set -euo pipefail

EXAMPLES_DIR="examples"
LOG_FILE="target/examples_test.log"

echo "=== Testing Examples ===" | tee "$LOG_FILE"
echo "Started at: $(date)" | tee -a "$LOG_FILE"

FAILURES=()

for example in "$EXAMPLES_DIR"/*.rs; do
    name=$(basename "$example" .rs)
    echo -n "Testing $name... " | tee -a "$LOG_FILE"

    # Compile
    if cargo build --example "$name" 2>> "$LOG_FILE"; then
        echo "COMPILED" | tee -a "$LOG_FILE"
    else
        echo "COMPILE FAILED" | tee -a "$LOG_FILE"
        FAILURES+=("$name")
    fi
done

echo "" | tee -a "$LOG_FILE"
echo "=== Summary ===" | tee -a "$LOG_FILE"
echo "Tested: $(ls "$EXAMPLES_DIR"/*.rs | wc -l) examples" | tee -a "$LOG_FILE"
echo "Failed: ${#FAILURES[@]}" | tee -a "$LOG_FILE"

if [ ${#FAILURES[@]} -gt 0 ]; then
    echo "Failures: ${FAILURES[*]}" | tee -a "$LOG_FILE"
    exit 1
fi

echo "All examples passed\!" | tee -a "$LOG_FILE"
exit 0
```

